+                    // Bug A (#70): file-backed CONCURRENT writes land in the
+                    // pager's write_set rather than being mirrored into this
+                    // connection's MemDatabase. Calling advance_commit_clock
+                    // here would advertise memdb visibility at the just-
+                    // committed seq — then the next `refresh_memdb_if_stale`
+                    // sees publication.seq == memdb.seq and skips the reload,
+                    // leaving memdb without our row. A subsequent
+                    // `SELECT WHERE id = ?` that consults memdb therefore
+                    // returns zero rows for a row we just committed.
+                    //
+                    // For in-memory databases the pager and memdb are the
+                    // same backing store, so advancing memdb visibility at
+                    // commit time is fine. For file-backed databases we
+                    // must follow the non-concurrent file-backed pattern
+                    // below and defer memdb visibility until a read boundary
+                    // forces a reload from the refreshed pager snapshot.
+                    let committed_seq = if self.pager.is_memory() {
+                        self.advance_commit_clock()
+                    } else {
+                        self.advance_commit_clock_without_memdb_visibility()
+                    };
                     self.finalize_concurrent_commit(plan, committed_seq);
                     self.finish_commit_clock(committed_seq);
